from typing import List, Dict, Any
from leann.api import PassageManager, LeannSearcher
from pathlib import Path
import json
from collections import Counter, defaultdict

def get_index_statistics(
    index_path: str
) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index.

Args:
    index_path: Path to the LEANN index file

Returns:
    Dictionary containing:
    {
        "total_passages": total number of passages,
        "metadata_fields": list of unique metadata field names,
        "field_value_counts": dictionary of field value counts
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""

    # Check if index path exists
    index_file = Path(index_path)
    if not index_file.exists():
        raise FileNotFoundError(f"Index metadata file not found: {index_path}")

    # Load the index using PassageManager
    try:
        pm = PassageManager(index_path)
    except FileNotFoundError:
        raise
    except Exception:
        raise FileNotFoundError(f"Index metadata file not found: {index_path}")

    # Initialize statistics containers
    total_passages = pm.num_passages if hasattr(pm, 'num_passages') else len(pm)
    all_fields = set()
    field_value_counts = defaultdict(Counter)

    # Iterate through all passages to gather statistics
    for i in range(total_passages):
        passage = pm.get_passage(i) if hasattr(pm, 'get_passage') else pm[i]

        # Extract metadata from passage
        if isinstance(passage, dict):
            metadata = passage.get('metadata', {})
        else:
            metadata = getattr(passage, 'metadata', {})

        # Track fields and their values
        for field, value in metadata.items():
            all_fields.add(field)
            field_value_counts[field][value] += 1

    # Convert Counter objects to regular dictionaries
    field_value_counts = {k: dict(v) for k, v in field_value_counts.items()}

    return {
        "total_passages": total_passages,
        "metadata_fields": sorted(list(all_fields)),
        "field_value_counts": field_value_counts
    }

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> Dict[str, Any]:
    """Analyze how well an index covers required metadata fields.

Args:
    index_path: Path to the LEANN index file
    required_fields: List of metadata field names that should be present

Returns:
    Dictionary containing:
    {
        "coverage_percentage": percentage of passages that have all required fields,
        "field_coverage": dictionary mapping field name to coverage percentage,
        "missing_fields": list of required fields not found in any passage
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""

    # Check if index path exists
    index_file = Path(index_path)
    if not index_file.exists():
        raise FileNotFoundError(f"Index metadata file not found: {index_path}")

    # Load the index using PassageManager
    try:
        pm = PassageManager(index_path)
    except FileNotFoundError:
        raise
    except Exception:
        raise FileNotFoundError(f"Index metadata file not found: {index_path}")

    total_passages = pm.num_passages if hasattr(pm, 'num_passages') else len(pm)

    # Handle empty index
    if total_passages == 0:
        return {
            "coverage_percentage": 0.0,
            "field_coverage": {field: 0.0 for field in required_fields},
            "missing_fields": required_fields
        }

    # Initialize tracking variables
    field_presence = {field: 0 for field in required_fields}
    passages_with_all_fields = 0
    all_fields_in_index = set()

    # Iterate through all passages
    for i in range(total_passages):
        passage = pm.get_passage(i) if hasattr(pm, 'get_passage') else pm[i]

        # Extract metadata from passage
        if isinstance(passage, dict):
            metadata = passage.get('metadata', {})
        else:
            metadata = getattr(passage, 'metadata', {})

        # Track all fields present in the index
        all_fields_in_index.update(metadata.keys())

        # Check which required fields are present in this passage
        has_all_required = True
        for field in required_fields:
            if field in metadata and metadata[field] is not None:
                field_presence[field] += 1
            else:
                has_all_required = False

        # Count passages that have all required fields
        if has_all_required:
            passages_with_all_fields += 1

    # Calculate coverage percentages
    coverage_percentage = (passages_with_all_fields / total_passages) * 100
    field_coverage = {
        field: (count / total_passages) * 100 
        for field, count in field_presence.items()
    }

    # Find missing fields (fields that don't appear in any passage)
    missing_fields = [
        field for field in required_fields 
        if field not in all_fields_in_index
    ]

    return {
        "coverage_percentage": coverage_percentage,
        "field_coverage": field_coverage,
        "missing_fields": missing_fields
    }
